# agentic_I2 skeptic-crosscheck · S10-T4-A-E2
def merge(defaults, file_cfg, env_cfg, matrix):
    out = dict(defaults)
    for layer in (file_cfg, env_cfg, matrix):
        for k, v in layer.items():
            if v is not None:
                out[k] = v
    return out

print(merge(
    {"log_level": "INFO", "jobs": 1},
    {"log_level": "WARNING"},
    {"log_level": "DEBUG", "jobs": None},
    {"log_level": "ERROR"},
))

